const data = $json.body;
const style = data.style || 'официальный';

// Форматируем суммы с копейками
const fmtAmt = n => {
  if (!n && n !== 0) return '0,00 рублей';
  return n.toLocaleString('ru-RU', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + ' рублей';
};

const docLines = (data.docs || []).map(d => {
  let line = `- УПД № ${d.doc_num} от ${d.doc_date}`;
  if (d.due_date) line += ` (срок оплаты: ${d.due_date})`;
  line += ` на сумму ${fmtAmt(d.amount)}`;
  if (d.over_amt > 0) line += ` — просрочено ${d.days_overdue} дн.`;
  return line;
}).join('\n') || '- документы не указаны';

const totalFmt   = fmtAmt(data.total_balance);
const overFmt    = fmtAmt(data.overdue_amount);
const hasOverdue = data.overdue_amount > 0;

const styleInstructions = {
  'мягкий': `Тон: вежливое первое напоминание. Предположи, что оплата задержалась по техническим причинам. Без угроз и последствий. Попроси уточнить сроки оплаты.`,
  'официальный': `Тон: официально-деловой, нейтральный. Только факты: задолженность, документы, сумма, срок. Попроси оплатить до конца текущей недели.`,
  'строгий': `Тон: строгий, настойчивый. Обязательно укажи последствия задержки оплаты:
- простой вагонов на станции отправления
- начисление платы за простой 3 000 руб./сутки за вагон (с НДС 20%)
- невозможность пополнить ЕЛС в АС ЭТРАН и оформить отправку маршрута
- срыв графика маршрутных отправок
Потребуй оплатить сегодня или до конца текущего дня.`
};

const prompt = `Ты — менеджер ООО «ТК «Велес», транспортная компания (железнодорожные перевозки сыпучих грузов).
Напиши письмо-напоминание об оплате задолженности клиенту ${data.client_name}.

${styleInstructions[style] || styleInstructions['официальный']}

Данные по задолженности:
Общая сумма к оплате: ${totalFmt}
${hasOverdue ? `Просроченная задолженность: ${overFmt}` : 'Просроченной задолженности нет'}

Документы:
${docLines}

Правила написания письма:
1. Открой письмо фразой: «ООО «ТК «Велес» выражает признательность за долгосрочное и результативное сотрудничество.»
2. Перечисли все УПД с точными суммами и датами — без округлений
3. Укажи точную итоговую сумму к оплате
4. Пиши конкретно и кратко — без общих слов и AI-клише
5. Не используй фразы: «надеемся что письмо найдёт вас», «не стесняйтесь обращаться», «мы ценим каждого клиента»
6. Подпись: Менеджер ООО «ТК «Велес»
7. Только текст письма — никаких пояснений, заголовков, markdown-разметки
8. Только русский язык, только кириллица`;

const requestBody = JSON.stringify({
  model: 'llama-3.3-70b-versatile',
  max_tokens: 1500,
  messages: [
    { role: 'system', content: 'Ты опытный менеджер транспортной компании. Пишешь чёткие деловые письма на русском языке без воды и AI-клише.' },
    { role: 'user',   content: prompt }
  ]
});

return [{ json: { requestBody } }];

const resp = $json;
const text = resp?.choices?.[0]?.message?.content || resp?.error?.message || '';
return [{ json: { text } }];
